// 当前单词索引
let currentIndex = 0;
let currentPage = 'home';

// 单词库切换状态：'ai' | 'general' | 'color' (固定为general)
let currentWordBank = 'general'; // 固定使用通用单词库

// 当前词性过滤：null 或具体的词性ID如 'noun', 'verb' 等
let currentPosFilter = null;

// 当前分类过滤：null 或具体的分类ID
let currentCategoryFilter = null;

// 获取当前使用的单词数据
function getCurrentWordsData() {
    let words;
    switch(currentWordBank) {
        case 'ai': words = aiWordsData; break;
        case 'color': words = colorWordsData; break;
        default: words = wordsData;
    }
    
    // 如果有词性过滤，返回过滤后的单词
    if (currentPosFilter) {
        words = words.filter(word => word.pos === currentPosFilter);
    }
    
    // 如果有分类过滤，返回过滤后的单词
    if (currentCategoryFilter) {
        words = words.filter(word => word.category === currentCategoryFilter);
    }
    
    return words;
}

// 设置词性过滤
function setPosFilter(pos) {
    // 清除分类过滤，避免冲突
    currentCategoryFilter = null;
    currentPosFilter = pos;
    currentIndex = 0;
    
    // 切换到通用单词库（词性分类只在通用单词库中）
    if (currentWordBank !== 'general') {
        currentWordBank = 'general';
        updateWordBankButtons();
    }
    
    updateWordDisplay();
    updateKeyboard();
    
    // 如果当前不在首页，切换到首页
    if (currentPage !== 'home') {
        switchPage('home');
        // 更新导航栏选中状态
        navItems.forEach(nav => nav.classList.remove('nav-active'));
        navItems[0].classList.add('nav-active');
    }
}

// 清除词性过滤
function clearPosFilter() {
    currentPosFilter = null;
    currentIndex = 0;
    updateWordDisplay();
    updateKeyboard();
}

// 设置分类过滤
function setCategoryFilter(category) {
    currentCategoryFilter = category;
    currentIndex = 0;
    updateWordDisplay();
    updateKeyboard();
    
    // 如果当前不在首页，切换到首页
    if (currentPage !== 'home') {
        switchPage('home');
        // 更新导航栏选中状态
        navItems.forEach(nav => nav.classList.remove('nav-active'));
        navItems[0].classList.add('nav-active');
    }
}

// 清除分类过滤
function clearCategoryFilter() {
    currentCategoryFilter = null;
    currentIndex = 0;
    updateWordDisplay();
    updateKeyboard();
}

