// 默认数据（后备方案）
function useDefaultData() {
    wordsData = [
        {
            word: "template",
            phonetic: "/ˈtemplət/",
            meaning: "n. 模板（可复用的工作流）",
            sentence: "I'll use this template for my project.",
            sentencePhonetic: "/aɪl juːz ðɪs ˈtemplət fɔː maɪ ˈprɒdʒekt/",
            letters: ["T", "E", "M", "P", "L", "A"],
            category: "technology"
        },
        {
            word: "apple",
            phonetic: "/ˈæpl/",
            meaning: "n. 苹果",
            sentence: "I eat an apple every day.",
            sentencePhonetic: "/aɪ iːt ən ˈæpl ˈevri deɪ/",
            letters: ["A", "P", "L", "E"],
            category: "food"
        }
    ];
    
    categoriesData = [
        { id: "daily", name: "日常生活", description: "常用日常词汇", icon: "🏠", totalWords: 100, learnedWords: 65 },
        { id: "business", name: "商务英语", description: "职场商务用语", icon: "💼", totalWords: 100, learnedWords: 30 }
    ];
    
    statsData = { totalCategories: 8, totalWords: 1250, masteredWords: 85 };
}

// 初始化
function init() {
    // 默认使用AI单词库
    const currentWords = getCurrentWordsData();
    if (currentWords.length > 0) {
        updateWordDisplay();
        updateKeyboard();
    }
    bindEvents();
    bindCategoryEvents();
    renderCategoryPage();
    renderWordsPage();
    renderAiPage();
    
    // 更新单词库切换按钮状态
    updateWordBankButtons();
}

// 渲染分类页面
function renderCategoryPage() {
    // 更新统计数据
    const statsContainer = document.querySelector('.category-stats');
    if (statsContainer && statsData) {
        const statItems = statsContainer.querySelectorAll('.stat-number');
        if (statItems[0]) statItems[0].textContent = statsData.totalCategories || categoriesData.length;
        if (statItems[1]) statItems[1].textContent = statsData.totalWords || wordsData.length;
        if (statItems[2]) statItems[2].textContent = statsData.masteredWords || 0;
    }
    
    // 渲染分类列表
    const categoryList = document.querySelector('.category-list');
    if (categoryList && categoriesData.length > 0) {
        categoryList.innerHTML = categoriesData.map(cat => `
            <div class="category-card" data-category="${cat.id}">
                <div class="category-icon">${cat.icon}</div>
                <div class="category-info">
                    <h3 class="category-name">${cat.name}</h3>
                    <p class="category-desc">${cat.description}</p>
                    <div class="category-progress">
                        <div class="progress-bar">
                            <div class="progress-fill" style="width: ${(cat.learnedWords / cat.totalWords * 100).toFixed(0)}%"></div>
                        </div>
                        <span class="progress-text">${cat.learnedWords}/${cat.totalWords}</span>
                    </div>
                </div>
                <span class="category-arrow">›</span>
            </div>
        `).join('');
        
        // 重新绑定分类卡片事件
        bindCategoryCardEvents();
    }
}

// 绑定分类卡片事件
function bindCategoryCardEvents() {
    const categoryCards = document.querySelectorAll('.category-card');
    categoryCards.forEach(card => {
        card.addEventListener('click', () => {
            const categoryId = card.dataset.category;
            const category = categoriesData.find(c => c.id === categoryId);
            if (category) {
                card.style.transform = 'scale(0.98)';
                setTimeout(() => {
                    card.style.transform = '';
                }, 150);
                
                // 切换到通用单词库并设置分类过滤
                if (currentWordBank !== 'general') {
                    currentWordBank = 'general';
                    updateWordBankButtons();
                }
                setCategoryFilter(categoryId);
                console.log(`进入分类: ${category.name}`);
            }
        });
    });
}

// 渲染单词本页面
function renderWordsPage() {
    if (posCategoriesData.length === 0) return;
    
    // 渲染词性分类网格
    const posGrid = document.querySelector('.pos-grid');
    if (posGrid) {
        posGrid.innerHTML = posCategoriesData.map(pos => `
            <div class="pos-card" data-pos="${pos.id}">
                <div class="pos-icon">${pos.icon}</div>
                <div class="pos-name">${pos.name}</div>
                <div class="pos-en">${pos.enName}</div>
                <div class="pos-count">${pos.totalWords}词</div>
            </div>
        `).join('');
        
        // 绑定词性卡片事件
        bindPosCardEvents();
    }
}

// 绑定词性卡片事件
function bindPosCardEvents() {
    const posCards = document.querySelectorAll('.pos-card');
    posCards.forEach(card => {
        card.addEventListener('click', () => {
            const posId = card.dataset.pos;
            const pos = posCategoriesData.find(p => p.id === posId);
            if (pos) {
                card.style.transform = 'scale(0.96)';
                setTimeout(() => {
                    card.style.transform = '';
                }, 150);
                
                // 设置词性过滤并跳转到首页
                setPosFilter(posId);
                console.log(`进入词性分类: ${pos.name} (${pos.enName})`);
            }
        });
    });
}

// 更新单词显示
function updateWordDisplay() {
    const currentWords = getCurrentWordsData();
    if (currentWords.length === 0) return;
    
    const currentWord = currentWords[currentIndex];
    
    wordEl.textContent = currentWord.word;
    phoneticEl.textContent = currentWord.phonetic;
    meaningEl.textContent = currentWord.meaning;
    sentenceEl.textContent = currentWord.sentence;
    sentencePhoneticEl.textContent = currentWord.sentencePhonetic;
    progressTextEl.textContent = `${currentIndex + 1}/${currentWords.length}`;
}

// 更新键盘高亮
function updateKeyboard() {
    const currentWords = getCurrentWordsData();
    if (currentWords.length === 0) return;
    
    const currentWord = currentWords[currentIndex];
    const wordLetters = currentWord.letters.map(l => l.toUpperCase());
    
    keys.forEach(key => {
        const letter = key.textContent.toUpperCase();
        if (wordLetters.includes(letter)) {
            key.classList.add('key-active');
        } else {
            key.classList.remove('key-active');
        }
    });
}

// 绑定事件
function bindEvents() {
    // 上一页按钮
    if (prevBtn) {
        prevBtn.addEventListener('click', () => {
            const currentWords = getCurrentWordsData();
            if (currentWords.length === 0) return;
            // 循环翻页：到第1个后回到最后1个
            currentIndex = (currentIndex - 1 + currentWords.length) % currentWords.length;
            updateWordDisplay();
            updateKeyboard();
        });
    }

    // 下一页按钮
    if (nextBtn) {
        nextBtn.addEventListener('click', () => {
            goNext();
        });
    }

    // 上一页按钮
    if (prevBtn) {
        prevBtn.addEventListener('click', () => {
            goPrev();
        });
    }
    
    // 播放按钮
    if (playBtn) {
        playBtn.addEventListener('click', () => {
            playAudio();
        });
    }
    
    // 键盘按钮
    keys.forEach(key => {
        key.addEventListener('click', () => {
            const letter = key.textContent;
            handleKeyPress(letter);
        });
    });
    
    // 导航项 - 对应三个单词库和页面
    // 单词(index 1) -> general + words页面, AI(index 2) -> ai + review页面, 分类(index 3) -> color + category页面
    const navPageWordBankMap = { 
        1: { page: 'words', bank: 'general' },
        2: { page: 'review', bank: 'ai' },
        3: { page: 'category', bank: 'color' }
    };
    navItems.forEach((item, index) => {
        item.addEventListener('click', (e) => {
            e.preventDefault();
            navItems.forEach(nav => nav.classList.remove('nav-active'));
            item.classList.add('nav-active');
            
            // 切换到对应的单词库和页面
            if (navPageWordBankMap[index]) {
                // switchWordBank(navPageWordBankMap[index].bank); // 已屏蔽单词库切换
                switchPage(navPageWordBankMap[index].page);
            } else {
                // 首页和设置页面保持原逻辑
                const pageNames = ['home', 'words', 'review', 'category', 'settings'];
                switchPage(pageNames[index]);
            }
        });
    });
}

// 页面切换函数
function switchPage(pageName) {
    currentPage = pageName;
    
    // 隐藏所有页面
    pages.forEach(page => {
        page.classList.remove('active');
    });
    
    // 显示目标页面
    const targetPage = document.querySelector(`.page-${pageName}`);
    if (targetPage) {
        targetPage.classList.add('active');
    }
    
    // 更新标题
    const titleEl = document.querySelector('.app-title');
    const titles = {
        home: '单词学习',
        words: '单词本',
        review: 'AI助手',
        category: '分类',
        settings: '设置'
    };
    if (titleEl && titles[pageName]) {
        titleEl.textContent = titles[pageName];
    }
}

// 绑定分类页面事件
function bindCategoryEvents() {
    // 搜索功能
    const searchInput = document.querySelector('.search-input');
    const searchBtn = document.querySelector('.search-btn');
    
    if (searchInput && searchBtn) {
        searchBtn.addEventListener('click', () => {
            performSearch(searchInput.value);
        });
        
        searchInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') {
                performSearch(searchInput.value);
            }
        });
    }
}

// 搜索功能
function performSearch(keyword) {
    if (!keyword.trim()) {
        // 如果搜索词为空，显示所有分类
        const categoryCards = document.querySelectorAll('.category-card');
        categoryCards.forEach(card => {
            card.style.display = 'flex';
        });
        return;
    }
    
    const categoryCards = document.querySelectorAll('.category-card');
    let hasResult = false;
    
    categoryCards.forEach(card => {
        const categoryName = card.querySelector('.category-name').textContent;
        const categoryDesc = card.querySelector('.category-desc').textContent;
        
        if (categoryName.includes(keyword) || categoryDesc.includes(keyword)) {
            card.style.display = 'flex';
            hasResult = true;
        } else {
            card.style.display = 'none';
        }
    });
    
    if (!hasResult) {
        console.log('未找到匹配的分类');
    }
}

// 播放音频（使用 Web Speech API）
function playAudio() {
    const currentWords = getCurrentWordsData();
    if (currentWords.length === 0) return;

    const currentWord = currentWords[currentIndex];

    // 检查浏览器是否支持语音合成
    if ('speechSynthesis' in window) {
        // 创建语音合成实例
        const utterance = new SpeechSynthesisUtterance(currentWord.word);
        utterance.lang = 'en-US';
        utterance.rate = 0.8;
        speechSynthesis.speak(utterance);

        // 播放例句
        setTimeout(() => {
            const sentenceUtterance = new SpeechSynthesisUtterance(currentWord.sentence);
            sentenceUtterance.lang = 'en-US';
            sentenceUtterance.rate = 0.8;
            speechSynthesis.speak(sentenceUtterance);
        }, 1000);
    } else {
        console.log('浏览器不支持语音合成');
        // 视觉反馈
        playBtn.style.transform = 'scale(0.9)';
        setTimeout(() => {
            playBtn.style.transform = 'scale(1)';
        }, 150);
    }
}

// 处理键盘按键
function handleKeyPress(letter) {
    const currentWords = getCurrentWordsData();
    if (currentWords.length === 0) return;

    const currentWord = currentWords[currentIndex];
    const wordLetters = currentWord.letters.map(l => l.toUpperCase());
    
    if (wordLetters.includes(letter.toUpperCase())) {
        // 正确的字母，播放发音
        if ('speechSynthesis' in window) {
            const utterance = new SpeechSynthesisUtterance(letter.toLowerCase());
            utterance.lang = 'en-US';
            speechSynthesis.speak(utterance);
        }
        
        // 视觉反馈
        const keyEl = Array.from(keys).find(k => k.textContent === letter.toUpperCase());
        if (keyEl) {
            keyEl.style.transform = 'scale(0.85)';
            keyEl.style.backgroundColor = '#4caf50';
            setTimeout(() => {
                keyEl.style.transform = 'scale(1)';
                keyEl.style.backgroundColor = '';
            }, 200);
        }
    }
}

// 更新时间
function updateTime() {
    const now = new Date();
    const hours = now.getHours().toString().padStart(2, '0');
    const minutes = now.getMinutes().toString().padStart(2, '0');
    const timeEl = document.querySelector('.time');
    if (timeEl) {
        timeEl.textContent = `${hours}:${minutes}`;
    }
}

// 启动应用
document.addEventListener('DOMContentLoaded', () => {
    loadData();
    updateTime();
    setInterval(updateTime, 60000); // 每分钟更新一次时间
    
    // 初始化模式开关
    initModeToggle();
});

// 模式开关状态（自动播放）
let modeToggleState = false;

// 初始化模式开关
function initModeToggle() {
    const modeToggle = document.querySelector('.mode-toggle');
    if (modeToggle) {
        modeToggle.addEventListener('click', () => {
            modeToggleState = !modeToggleState;
            modeToggle.classList.toggle('active', modeToggleState);
            
            const toggleCircle = modeToggle.querySelector('.toggle-circle');
            if (toggleCircle) {
                toggleCircle.style.transform = modeToggleState ? 'translateX(16px)' : 'translateX(0)';
            }
            
            console.log('模式开关状态:', modeToggleState ? '开启（自动播放）' : '关闭');
            
            // 如果开启自动播放且在首页，立即开始播放
            if (modeToggleState && currentPage === 'home') {
                playCurrentWord();
            }
        });
        
        // 页面切换时检查是否需要自动播放
        observePageChange();
    }
}

// 监听页面切换
function observePageChange() {
    const originalSwitchPage = window.switchPage;
    window.switchPage = function(pageName) {
        // 离开首页时关闭自动学习
        if (currentPage === 'home') {
            if (modeToggleState) {
                modeToggleState = false;
                const modeToggle = document.querySelector('.mode-toggle');
                if (modeToggle) {
                    modeToggle.classList.remove('active');
                    const toggleCircle = modeToggle.querySelector('.toggle-circle');
                    if (toggleCircle) {
                        toggleCircle.style.transform = 'translateX(0)';
                    }
                }
                console.log('离开首页，自动学习已关闭');
            }
        }
        
        // 调用原始函数
        originalSwitchPage(pageName);
    };
}

// 播放当前单词和句子
function playCurrentWord() {
    const words = getCurrentWordsData();
    if (words.length === 0) return;
    
    const word = words[currentIndex];
    if (word) {
        // 先播放单词
        playWord(word.word, () => {
            // 单词播放完成后，等待1秒播放句子
            setTimeout(() => {
                if (word.sentence && modeToggleState) {
                    // 播放句子
                    playWord(word.sentence, () => {
                        // 句子播放完成后，等待1.5秒跳转到下一个单词
                        if (modeToggleState) {
                            setTimeout(() => {
                                goNext();
                            }, 1500);
                        }
                    });
                } else if (modeToggleState) {
                    // 如果没有句子，直接跳转
                    setTimeout(() => {
                        goNext();
                    }, 1500);
                }
            }, 1000);
        });
    }
}

// 跳转到下一个单词
function goNext() {
    const currentWords = getCurrentWordsData();
    if (currentWords.length === 0) return;
    // 循环翻页：到最后1个后回到第1个
    currentIndex = (currentIndex + 1) % currentWords.length;
    updateWordDisplay();
    updateKeyboard();
    // 如果自动学习开启，继续播放
    if (modeToggleState) {
        setTimeout(() => {
            playCurrentWord();
        }, 500);
    }
}

// 跳转到上一个单词
function goPrev() {
    const currentWords = getCurrentWordsData();
    if (currentWords.length === 0) return;
    // 循环翻页：到第1个后回到最后1个
    currentIndex = (currentIndex - 1 + currentWords.length) % currentWords.length;
    updateWordDisplay();
    updateKeyboard();
}

// 播放单词（带回调）
function playWord(wordText, onEnd) {
    if ('speechSynthesis' in window) {
        const utterance = new SpeechSynthesisUtterance(wordText);
        utterance.lang = 'en-US';
        utterance.rate = 0.8;
        utterance.pitch = 1;
        
        if (onEnd) {
            utterance.onend = onEnd;
        }
        
        speechSynthesis.speak(utterance);
    } else if (onEnd) {
        // 如果浏览器不支持语音合成，仍然执行回调
        onEnd();
    }
}

// 渲染AI页面
function renderAiPage() {
    if (aiWordsData.length === 0 || aiCategoriesData.length === 0) return;
    
    // 渲染AI工具分类卡片
    const aiGrid = document.querySelector('.ai-grid');
    if (aiGrid) {
        aiGrid.innerHTML = aiCategoriesData.map(cat => `
            <div class="ai-card" data-ai="${cat.id}">
                <div class="ai-icon">${cat.icon}</div>
                <div class="ai-name">${cat.name}</div>
                <div class="ai-desc">${cat.description}</div>
            </div>
        `).join('');
        
        // 绑定AI卡片事件
        bindAiCardEvents();
    }
    
    // 渲染AI词汇列表
    const aiWordsList = document.querySelector('.ai-words-list');
    if (aiWordsList) {
        aiWordsList.innerHTML = aiWordsData.map(word => `
            <div class="ai-word-item">
                <div class="ai-word-info">
                    <span class="ai-word-name">${word.word}</span>
                    <span class="ai-word-phonetic">${word.phonetic}</span>
                </div>
            </div>
        `).join('');
    }
}

// 绑定AI卡片事件
function bindAiCardEvents() {
    const aiCards = document.querySelectorAll('.ai-card');
    aiCards.forEach(card => {
        card.addEventListener('click', () => {
            const aiId = card.dataset.ai;
            const aiCat = aiCategoriesData.find(c => c.id === aiId);
            if (aiCat) {
                card.style.transform = 'scale(0.96)';
                setTimeout(() => {
                    card.style.transform = '';
                }, 150);
                
                // 切换到AI单词库并设置分类过滤
                if (currentWordBank !== 'ai') {
                    currentWordBank = 'ai';
                    updateWordBankButtons();
                }
                setCategoryFilter(aiId);
                console.log(`进入AI分类: ${aiCat.name}`);
            }
        });
    });
}

// 切换到指定单词库
function switchWordBank(bank) {
    if (currentWordBank === bank) return;

    currentWordBank = bank;
    currentIndex = 0; // 重置到第一个单词
    currentPosFilter = null; // 清除词性过滤
    currentCategoryFilter = null; // 清除分类过滤
    updateWordDisplay();
    updateKeyboard();
    updateWordBankButtons();
}

// 更新单词库切换按钮显示
function updateWordBankButtons() {
    const buttons = document.querySelectorAll('.word-bank-btn');
    buttons.forEach(btn => {
        const bank = btn.dataset.bank;
        btn.classList.toggle('active', bank === currentWordBank);
    });
}

